macro.implementation:
do {
  osalSysLockFromISR();
  osalThreadResumeI(&(siop)->sync_rx, SIO_MSG_ERRORS);
  osalThreadResumeI(&(siop)->sync_rxidle, SIO_MSG_ERRORS);
  osalSysUnlockFromISR();
} while (false)

do {
  osalSysLockFromISR();
  osalThreadResumeI(&(siop)->sync_rx, MSG_OK);
  osalSysUnlockFromISR();
} while (false)

do {
  osalSysLockFromISR();
  osalThreadResumeI(&(siop)->sync_rxidle, MSG_OK);
  osalSysUnlockFromISR();
} while (false)

do {
  osalSysLockFromISR();
  osalThreadResumeI(&(siop)->sync_tx, MSG_OK);
  osalSysUnlockFromISR();
} while (false)

do {
  osalSysLockFromISR();
  osalThreadResumeI(&(siop)->sync_txend, MSG_OK);
  osalSysUnlockFromISR();
} while (false)

method.implementation:
msg_t msg;

msg = sioSynchronizeTX(self, TIME_INFINITE);
if (msg != MSG_OK) {
  return msg;
}

sioPutX(self, b);
return MSG_OK;

msg_t msg;

while (true) {
  msg = sioSynchronizeRX(self, TIME_INFINITE);
  if (msg == SIO_MSG_ERRORS) {
    (void)sioGetAndClearErrors(self);
    continue;
  }
  if (msg != MSG_OK) {
    return msg;
  }

  return sioGetX(self);
}

(void)self;
(void)b;

return STM_RESET;

msg_t msg;

msg = sioSynchronizeTX(self, timeout);
if (msg != MSG_OK) {
  return msg;
}

sioPutX(self, b);
return MSG_OK;

msg_t msg;

while (true) {
  msg = sioSynchronizeRX(self, timeout);
  if (msg == SIO_MSG_ERRORS) {
    (void)sioGetAndClearErrors(self);
    continue;
  }
  if (msg != MSG_OK) {
    return msg;
  }

  return sioGetX(self);
}

switch (operation) {
case CHN_CTL_NOP:
  osalDbgCheck(arg == NULL);
  break;
case CHN_CTL_INVALID:
  return HAL_RET_UNKNOWN_CTL;
default:
  /* Delegating to the LLD if supported.*/
  return sio_lld_control(self, operation, arg);
}
return HAL_RET_SUCCESS;

fields.verbatim:
#if defined(SIO_DRIVER_EXT_FIELDS)
SIO_DRIVER_EXT_FIELDS
#endif
/* End of the mandatory fields.*/
sio_lld_driver_fields;

objinit.implementation:
self->enabled     = (sioevents_t)0;
self->cb          = NULL;
#if SIO_USE_SYNCHRONIZATION == TRUE
self->sync_rx     = NULL;
self->sync_rxidle = NULL;
self->sync_tx     = NULL;
self->sync_txend  = NULL;
#endif

/* Optional, user-defined initializer.*/
#if defined(SIO_DRIVER_EXT_INIT_HOOK)
SIO_DRIVER_EXT_INIT_HOOK(self);
#endif

method.implementation:
osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert(self->state == HAL_DRV_STATE_READY, "invalid state");
sioWriteEnableFlagsX(self, mask);
osalSysUnlock();

osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert(self->state == HAL_DRV_STATE_READY, "invalid state");
sioSetEnableFlagsX(self, mask);
osalSysUnlock();

osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert(self->state == HAL_DRV_STATE_READY, "invalid state");
sioClearEnableFlagsX(self, mask);
osalSysUnlock();

sioevents_t errors;

osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert(self->state == HAL_DRV_STATE_READY, "invalid state");
errors = sioGetAndClearErrorsX(self);
osalSysUnlock();

return errors;

sioevents_t events;

osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert(self->state == HAL_DRV_STATE_READY, "invalid state");
events = sioGetAndClearEventsX(self, mask);
osalSysUnlock();

return events;

sioevents_t events;

osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert(self->state == HAL_DRV_STATE_READY, "invalid state");
events = sioGetEventsX(self);
osalSysUnlock();

return events;

msg_t msg;

osalDbgCheck(self != NULL);

osalSysLock();

osalDbgAssert(self->state == HAL_DRV_STATE_READY, "invalid state");

/* Checking for errors before going to sleep.*/
if (sioHasRXErrorsX(self)) {
  osalSysUnlock();
  return SIO_MSG_ERRORS;
}

msg = MSG_OK;
/*lint -save -e506 -e681 [2.1] Silencing this error because it is
  tested with a template implementation of sio_lld_is_rx_empty() which
  is constant.*/
while (sioIsRXEmptyX(self)) {
/*lint -restore*/
  msg = osalThreadSuspendTimeoutS(&self->sync_rx, timeout);
  if (msg != MSG_OK) {
    break;
  }
}

osalSysUnlock();

return msg;

msg_t msg;

osalDbgCheck(self != NULL);

osalSysLock();

osalDbgAssert(self->state == HAL_DRV_STATE_READY, "invalid state");

/* Checking for errors before going to sleep.*/
if (sioHasRXErrorsX(self)) {
  osalSysUnlock();
  return SIO_MSG_ERRORS;
}

msg = MSG_OK;
/*lint -save -e506 -e681 [2.1] Silencing this error because it is
  tested with a template implementation of sio_lld_is_rx_empty() which
  is constant.*/
while (!sioIsRXIdleX(self)) {
/*lint -restore*/
  msg = osalThreadSuspendTimeoutS(&self->sync_rxidle, timeout);
  if (msg != MSG_OK) {
    break;
  }
}

osalSysUnlock();

return msg;

msg_t msg;

osalDbgCheck(self != NULL);

osalSysLock();

osalDbgAssert(self->state == HAL_DRV_STATE_READY, "invalid state");

msg = MSG_OK;
/*lint -save -e506 -e681 [2.1] Silencing this error because it is
  tested with a template implementation of sio_lld_is_tx_full() which
  is constant.*/
while (sioIsTXFullX(self)) {
/*lint -restore*/
  msg = osalThreadSuspendTimeoutS(&self->sync_tx, timeout);
  if (msg != MSG_OK) {
    break;
  }
}

osalSysUnlock();

return msg;

msg_t msg;

osalDbgCheck(self != NULL);

osalSysLock();

osalDbgAssert(self->state == HAL_DRV_STATE_READY, "invalid state");

/*lint -save -e506 -e774 [2.1, 14.3] Silencing this error because
  it is tested with a template implementation of sio_lld_is_tx_ongoing()
  which is constant.*/
if (sioIsTXOngoingX(self)) {
/*lint -restore*/
  msg = osalThreadSuspendTimeoutS(&self->sync_txend, timeout);
}
else {
  msg = MSG_OK;
}

osalSysUnlock();

return msg;

msg_t msg;

if (config != NULL) {
  self->config = config;
}

msg = sio_lld_start(self);
if (msg == HAL_RET_SUCCESS) {
#if SIO_USE_SYNCHRONIZATION == TRUE
  /* If synchronization is enabled then all events by default.*/
  sioWriteEnableFlagsX(self, SIO_EV_ALL_EVENTS);
#else
  /* If synchronization is disabled then no events by default.*/
  sioWriteEnableFlagsX(self, SIO_EV_NONE);
#endif
}
else {
  self->config = NULL;
}

return msg;

sio_lld_stop(self);
self->cb      = NULL;
self->enabled = (sioevents_t)0;

#if SIO_USE_SYNCHRONIZATION == TRUE
/* Informing waiting threads, if any.*/
osalThreadResumeI(&self->sync_rx, MSG_RESET);
osalThreadResumeI(&self->sync_rxidle, MSG_RESET);
osalThreadResumeI(&self->sync_tx, MSG_RESET);
osalThreadResumeI(&self->sync_txend, MSG_RESET);
osalOsRescheduleS();
#endif

(void)self;
(void)b;

return STM_RESET;

(void)self;
(void)mask;

return 0;

(void)self;
(void)operation;
(void)arg;

return 0;

objinit.implementation:
__drv_objinit_impl(self, vmt);

{
  static const struct asynchronous_channel_vmt bsio_chn_vmt = {
    .instance_offset      = offsetof(hal_buffered_sio_c, chn),
    .write                = __bsio_chn_write_impl,
    .read                 = __bsio_chn_read_impl,
    .put                  = __bsio_chn_put_impl,
    .get                  = __bsio_chn_get_impl,
    .unget                = __bsio_chn_unget_impl,
    .writet               = __bsio_chn_writet_impl,
    .readt                = __bsio_chn_readt_impl,
    .putt                 = __bsio_chn_putt_impl,
    .gett                 = __bsio_chn_gett_impl,
    .getclr               = __bsio_chn_getclr_impl,
    .ctl                  = __bsio_chn_ctl_impl
  };
  oopIfObjectInit(&self->chn, &bsio_chn_vmt);
}

osalEventObjectInit(&self->event);
iqObjectInit(&self->iqueue, ib, ibsize, NULL, NULL);
oqObjectInit(&self->oqueue, ob, obsize, __bsio_onotify, (void *)self);
drvSetArgumentX(siop, self);
self->siop = siop;

method.implementation:
msg_t msg;

/* Starting the undelying SIO driver.*/
msg = drvStart(self->siop, config);
if (msg == HAL_RET_SUCCESS) {
  self->config = self->siop->config;
  drvSetArgumentX(self->siop, self);
  drvSetCallbackX(self->siop, &__bsio_default_cb);
  sioWriteEnableFlagsX(self->siop,
                       SIO_EV_ALL_ERRORS | SIO_EV_RX_NOTEMPTY |
                       SIO_EV_RX_IDLE);
}

return msg;

osalDbgCheckClassI();
osalDbgCheck(self != NULL);

if (iqIsEmptyI(&self->iqueue)) {
  bsAddFlagsI(self, CHN_FL_RX_NOTEMPTY);
}

if (iqPutI(&self->iqueue, b) < MSG_OK) {
  bsAddFlagsI(self, CHN_FL_BUFFER_FULL_ERR);
}

msg_t b;

osalDbgCheckClassI();
osalDbgCheck(self != NULL);

b = oqGetI(&self->oqueue);
if (b < MSG_OK) {
  /* Note, this event is only added when the buffer becomes fully empty in
     order to avoid continuous reporting.*/
  bsAddFlagsI(self, CHN_FL_TX_NOTFULL);
}

return b;

function.implementation:
msg_t msg;

msg = sioSynchronizeTX(siop, timeout);
if (msg != MSG_OK) {
  return 0U;
}

return sioAsyncWriteX(siop, bp, n);

msg_t msg;

msg = sioSynchronizeRX(siop, timeout);
if (msg == SIO_MSG_ERRORS) {
  (void)sioGetAndClearErrors(siop);
}
else if (msg != MSG_OK) {
  return 0U;
}

return sioAsyncReadX(siop, bp, n);

sioevents_t current;
sioevents_t mask;

current = sioGetEnableFlagsX(bsiop->siop);
mask = current & ~(SIO_EV_TX_NOTFULL | SIO_EV_TX_END);
if (!oqIsEmptyI(&bsiop->oqueue)) {
  mask |= SIO_EV_TX_NOTFULL;
}
if (txdone) {
  mask |= SIO_EV_TX_END;
}
if (mask != current) {
  sioWriteEnableFlagsX(bsiop->siop, mask);
}

bool txdone;

txdone = sioIsTXOngoingX(bsiop->siop);
while (!sioIsTXFullX(bsiop->siop)) {
  msg_t msg;

  msg = oqGetI(&bsiop->oqueue);
  if (msg < MSG_OK) {
    bsAddFlagsI(bsiop, CHN_FL_TX_NOTFULL);
    __bsio_update_tx_irq(bsiop, txdone);
    return;
  }
  sioPutX(bsiop->siop, (uint_fast16_t)msg);
  txdone = true;
}

__bsio_update_tx_irq(bsiop, txdone);

/* RX FIFO needs to be fully emptied or SIO will not generate more RX FIFO
   events.*/
while (!sioIsRXEmptyX(bsiop->siop)) {
  bsIncomingDataI(bsiop, sioGetX(bsiop->siop));
}

hal_sio_driver_c *siop = (hal_sio_driver_c *)ip;
hal_buffered_sio_c *bsiop = (hal_buffered_sio_c *)siop->arg;
sioevents_t events;

if (bsiop == NULL) {
  return;
}

osalSysLockFromISR();

/* Drain/fill FIFOs before re-enabling data interrupts in the LLD.
   NOTE: this assumes status/error flags are not cleared by data reads,
   otherwise non-data events could be lost before sioGetAndClearEventsX(). */
if (!sioIsRXEmptyX(siop)) {
  __bsio_pop_data(bsiop);
}
if (!sioIsTXFullX(siop)) {
  __bsio_push_data(bsiop);
}

/* Posting the non-data SIO events as channel event flags, the masks are
   made to match.*/
events = sioGetAndClearEventsX(siop, SIO_EV_ALL_EVENTS);
bsAddFlagsI(bsiop, (eventflags_t)(events & ~SIO_EV_ALL_DATA));

osalSysUnlockFromISR();
